247→        // v1.0 텍스트 프로토콜 (기존 방식)
248→        private void ThreadTask1_V1()
249→        {
250→            // 시작 시 버퍼 클리어
251→            if (SerialAduino.BytesToRead > 0)
252→                SerialAduino.DiscardInBuffer();
253→
254→            while (SerialAduino.IsOpen)
255→            {
256→                try
257→                {
258→                    string incoming = SerialAduino.ReadLine();
259→
260→                    if (!string.IsNullOrEmpty(incoming))
261→                    {
262→                        // 버퍼에 쌓인 데이터 있으면 버리고 최신 데이터만 사용
263→                        if (SerialAduino.BytesToRead > 0)
264→                            SerialAduino.DiscardInBuffer();
265→
266→                        string line = incoming.Trim();
267→                        // 디버그: 수신 데이터 로깅
268→                        System.Diagnostics.Debug.WriteLine($"[Arduino V1] Raw: '{line}' (len={line.Length})");
269→
270→                        if (line.StartsWith("S") && line.EndsWith("E") && line.Length == 34)
271→                        {
272→                            // DI 파싱 (16비트)
273→                            for (int i = 0; i < 16; i++)
274→                            {
275→                                IO.IN[i] = (line.Substring(i + 1, 1) == "1");
276→                            }
277→                            // 디버그: IO.IN 상태 로깅
278→                            string ioStatus = string.Join("", IO.IN.Take(8).Select(b => b ? "1" : "0"));
279→                            System.Diagnostics.Debug.WriteLine($"[Arduino V1] IO.IN[0-7]: {ioStatus}");
280→
281→                            // UI 업데이트 - 비동기 일괄 처리 (btnIn은 8개)
282→                            this.BeginInvoke(new MethodInvoker(() =>
283→                            {
284→                                for (int i = 0; i < btnIn.Length; i++)
285→                                {
286→                                    if (IO.IN[i])
287→                                    {
288→                                        btnIn[i].BackColor = pColor.Theme.LightRed;
289→                                        btnIn[i].ForeColor = System.Drawing.Color.Black;
290→                                    }
291→                                    else
292→                                    {
293→                                        btnIn[i].BackColor = pColor.Theme.DeepRed;
294→                                        btnIn[i].ForeColor = System.Drawing.Color.White;
295→                                    }
296→                                }
297→                            }));
298→
299→                            // 아날로그 파싱 (for문 밖에서 1번만)
300→                            try
301→                            {
302→                                double raw1 = Convert.ToDouble(line.Substring(17, 4));
303→                                double raw2 = Convert.ToDouble(line.Substring(21, 4));
304→                                double raw3 = Convert.ToDouble(line.Substring(25, 4));
305→
306→                                if (GlobalValues.weldMode == "SPOT")
307→                                {
308→                                    // SPOT 모드: 전류/온도/공압 (전류 단위: kA)
309→                                    double ampRaw = (raw1 / 100.0 * 3.0) * Amp.Tol;
310→                                    double tempRaw = ((raw2 / 100.0 * 25.0) - 25.0) * Volt.Tol;
311→                                    double airRaw = (((raw3 / 100.0 * 0.25) - 0.25) * 10.204) * Flow.Tol;
312→
313→                                    Amp.Value = Math.Max(0, Math.Round(AmpFilter.Update(ampRaw), 1));
314→                                    Volt.Value = Math.Max(0, Math.Round(VoltFilter.Update(tempRaw), 1));
315→                                    Flow.Value = Math.Max(0, Math.Round(FlowFilter.Update(airRaw), 1));
316→                                }
317→                                else
318→                                {
319→                                    // CO2 모드: 전류/전압/유량
320→                                    double ampRaw = (raw1 / 100.0 * 60.0) * Amp.Tol;
321→                                    double voltRaw = (raw2 / 100.0 * 25.0) * Volt.Tol;
322→                                    double flowRaw = ((raw3 / 100.0 * 12.5) - 12.5) * Flow.Tol;
323→
324→                                    Amp.Value = Math.Max(0, Math.Round(AmpFilter.Update(ampRaw), 1));
325→                                    Volt.Value = Math.Max(0, Math.Round(VoltFilter.Update(voltRaw), 1));
326→                                    Flow.Value = Math.Max(0, Math.Round(FlowFilter.Update(flowRaw), 1));
327→                                }
328→
329→                                // UI 업데이트 - 비동기
330→                                this.BeginInvoke(new MethodInvoker(() =>
331→                                {
332→                                    labelAmp.Text = Amp.Value.ToString("0.00");
333→                                    labelVolt.Text = Volt.Value.ToString("0.00");
334→                                    labelFlow.Text = Flow.Value.ToString("0.00");
335→                                }));
336→                            }
337→                            catch (Exception parseEx)
338→                            {
339→                                Logger.Log(LanguageManager.Get("log_analog_parse_error", parseEx.Message));
340→                            }
341→                        }
342→                    }
343→                }
344→                catch (Exception ex)
345→                {
346→                }
347→                Thread.Sleep(1);
348→            }
349→        }
