 17→    public class FilteredValue
 18→    {
 19→        private double filtered = 0;
 20→        private readonly double alpha;
 21→
 22→        public FilteredValue(double alpha)
 23→        {
 24→            this.alpha = alpha;
 25→        }
 26→
 27→        public double Update(double newValue)
 28→        {
 29→            filtered = alpha * newValue + (1 - alpha) * filtered;
 30→            return filtered;
 31→        }
 32→    }
