  7→namespace WeldMonitor3
  8→{
  9→    public static class Logger
 10→    {
 11→        private static TextBox _targetTextBox;
 12→
 13→        // 비동기 파일 로깅용
 14→        private static ConcurrentQueue<string> _logQueue = new ConcurrentQueue<string>();
 15→        private static Thread _fileLogThread;
 16→        private static bool _isRunning = false;
 17→        private static string _logBaseFolder;
 18→        private static readonly object _fileLock = new object();
 19→        private const int MAX_QUEUE_SIZE = 10000;  // 큐 최대 크기 제한 (메모리 보호)
 20→
 21→        public static void Initialize(TextBox targetTextBox)
 22→        {
 23→            _targetTextBox = targetTextBox;
 24→
 25→            // 로그 폴더 설정 (프로그램 실행 경로\Log)
 26→            _logBaseFolder = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "Log");
 27→
 28→            // 파일 로깅 스레드 시작
 29→            StartFileLogging();
 30→        }
 31→
 32→        /// <summary>
 33→        /// 파일 로깅 스레드 시작
 34→        /// </summary>
 35→        private static void StartFileLogging()
 36→        {
 37→            if (_isRunning) return;
 38→
 39→            _isRunning = true;
 40→            _fileLogThread = new Thread(FileLogWorker)
 41→            {
 42→                IsBackground = true,
 43→                Name = "FileLogThread"
 44→            };
 45→            _fileLogThread.Start();
 46→        }
 47→
 48→        /// <summary>
 49→        /// 파일 로깅 스레드 종료
 50→        /// </summary>
 51→        public static void Shutdown()
 52→        {
 53→            _isRunning = false;
 54→
 55→            // 남은 로그 모두 기록
 56→            FlushLogs();
 57→
 58→            if (_fileLogThread != null && _fileLogThread.IsAlive)
 59→            {
 60→                _fileLogThread.Join(1000); // 최대 1초 대기
 61→            }
 62→        }
 63→
 64→        /// <summary>
 65→        /// 파일 로깅 워커 스레드
 66→        /// </summary>
 67→        private static void FileLogWorker()
 68→        {
 69→            while (_isRunning)
 70→            {
 71→                try
 72→                {
 73→                    // 큐에서 로그 메시지 꺼내서 파일에 기록
 74→                    while (_logQueue.TryDequeue(out string logMessage))
 75→                    {
 76→                        WriteToFile(logMessage);
 77→                    }
 78→
 79→                    // CPU 부하 방지 (50ms 대기)
 80→                    Thread.Sleep(50);
 81→                }
 82→                catch
 83→                {
 84→                    // 로깅 스레드 오류 무시 (검사에 영향 X)
 85→                }
 86→            }
 87→
 88→            // 종료 시 남은 로그 처리
 89→            FlushLogs();
 90→        }
 91→
 92→        /// <summary>
 93→        /// 남은 로그 모두 파일에 기록
 94→        /// </summary>
 95→        private static void FlushLogs()
 96→        {
 97→            while (_logQueue.TryDequeue(out string logMessage))
 98→            {
 99→                WriteToFile(logMessage);
100→            }
101→        }
102→
103→        /// <summary>
104→        /// 파일에 로그 기록 (년\월\일 폴더 구조)
105→        /// </summary>
106→        private static void WriteToFile(string message)
107→        {
108→            try
109→            {
110→                DateTime now = DateTime.Now;
111→
112→                // 폴더 경로: Log\2026\01\10
113→                string folderPath = Path.Combine(
114→                    _logBaseFolder,
115→                    now.Year.ToString(),
116→                    now.Month.ToString("D2"),
117→                    now.Day.ToString("D2")
118→                );
119→
120→                // 폴더 생성
121→                if (!Directory.Exists(folderPath))
122→                {
123→                    Directory.CreateDirectory(folderPath);
124→                }
125→
126→                // 파일 경로: Log\2026\01\10\log_20260110.txt
127→                string fileName = $"log_{now:yyyyMMdd}.txt";
128→                string filePath = Path.Combine(folderPath, fileName);
129→
130→                // 파일에 추가 기록
131→                lock (_fileLock)
132→                {
133→                    File.AppendAllText(filePath, message + Environment.NewLine);
134→                }
135→            }
136→            catch
137→            {
138→                // 파일 기록 실패 시 무시 (검사에 영향 X)
139→            }
140→        }
141→
142→        /// <summary>
143→        /// 로그 출력 (TextBox + 파일)
144→        /// </summary>
145→        public static void Log(string message)
146→        {
147→            string time = DateTime.Now.ToString("HH:mm:ss.fff");
148→            string formattedMessage = $"[{time}] {message}";
149→
150→            // 파일 로깅 큐에 추가 (비동기) - 최대 크기 초과 시 오래된 항목 제거
151→            if (_logQueue.Count >= MAX_QUEUE_SIZE)
152→            {
153→                _logQueue.TryDequeue(out _);  // 오래된 로그 1개 버림
154→            }
155→            _logQueue.Enqueue(formattedMessage);
156→
157→            // TextBox 출력
