125→        static List<WeldRecord> LoadRecords(string jigId, DateTime startDate, DateTime endDate)
126→        {
127→            string baseDir = GlobalValues.GetDataPath();
128→            var records = new List<WeldRecord>();
129→            int weldNo = 1;
130→
131→            for (DateTime date = startDate; date <= endDate; date = date.AddDays(1))
132→            {
133→                string folder = Path.Combine(baseDir, date.ToString("yyyy"), date.ToString("MM"), date.ToString("dd"));
134→                if (!Directory.Exists(folder)) continue;
135→
136→                // JIG ID로 필터: 파일명 패턴 *_{jigId}_serial.csv
137→                var files = Directory.GetFiles(folder, "*.csv")
138→                    .Where(f => Path.GetFileName(f).Contains($"_{jigId}_"))
139→                    .OrderBy(f => f)
140→                    .ToArray();
141→
142→                foreach (var file in files)
143→                {
144→                    try
145→                    {
146→                        var lines = File.ReadAllLines(file, Encoding.UTF8);
147→                        if (lines.Length < 2) continue;
148→
149→                        // 첫 줄 헤더, 나머지 데이터
150→                        for (int i = 1; i < lines.Length; i++)
151→                        {
152→                            if (string.IsNullOrWhiteSpace(lines[i])) continue;
153→                            var cols = lines[i].Split(',');
154→                            if (cols.Length < 13) continue;
155→
156→                            // 파일명에서 날짜/시간 추출
157→                            string fName = Path.GetFileNameWithoutExtension(file);
158→                            string fileDate = "";
159→                            string fileTime = "";
160→                            // 파일명: yyyyMMdd_HHmmss-RESULT_JIGID_serial
161→                            if (fName.Length >= 15)
162→                            {
163→                                fileDate = $"{fName.Substring(0, 4)}-{fName.Substring(4, 2)}-{fName.Substring(6, 2)}";
164→                                fileTime = $"{fName.Substring(9, 2)}:{fName.Substring(11, 2)}:{fName.Substring(13, 2)}";
165→                            }
166→
167→                            var rec = new WeldRecord
168→                            {
169→                                WeldNo = weldNo++,
170→                                Date = fileDate,
171→                                Time = fileTime,
172→                                Result = SafeStr(cols, 12),
