178→                            rec.Volt = SafeDouble(cols, 6);     // V_Meas.
179→                            rec.Gas = SafeDouble(cols, 9);      // F_Meas.
180→
181→                            // 기준값 (Spec 컬럼)
182→                            rec.AmpSpecMin = SafeDouble(cols, 2);   // A_S.Min
