185→                            rec.VoltSpecMax = SafeDouble(cols, 7);  // V_S.Max
186→                            rec.GasSpecMin = SafeDouble(cols, 8);   // F_S.Min
187→                            rec.GasSpecMax = SafeDouble(cols, 10);  // F_S.Max
188→
189→                            records.Add(rec);
190→                        }
191→                    }
